import{_ as e,o as a,c as l,a4 as n}from"./chunks/framework._in6GHBg.js";const p=JSON.parse('{"title":"英语解题速查卡","description":"","frontmatter":{},"headers":[],"relativePath":"english/Eng-Review-Tool-002-英语解题速查卡-V1.0-20260405.md","filePath":"english/Eng-Review-Tool-002-英语解题速查卡-V1.0-20260405.md"}'),s={name:"english/Eng-Review-Tool-002-英语解题速查卡-V1.0-20260405.md"};function i(r,t,o,d,h,g){return a(),l("div",null,[...t[0]||(t[0]=[n(`<h1 id="英语解题速查卡" tabindex="-1">英语解题速查卡 <a class="header-anchor" href="#英语解题速查卡" aria-label="Permalink to &quot;英语解题速查卡&quot;">​</a></h1><p><strong>考前30分钟快速浏览——核心技巧与模板</strong></p><hr><h2 id="一、阅读理解" tabindex="-1">一、阅读理解 <a class="header-anchor" href="#一、阅读理解" aria-label="Permalink to &quot;一、阅读理解&quot;">​</a></h2><h3 id="四步法" tabindex="-1">四步法 <a class="header-anchor" href="#四步法" aria-label="Permalink to &quot;四步法&quot;">​</a></h3><ol><li><strong>速读抓主旨</strong>（首尾段）</li><li><strong>看题划关键词</strong></li><li><strong>定位找答案</strong></li><li><strong>同义替换选</strong></li></ol><h3 id="题型技巧" tabindex="-1">题型技巧 <a class="header-anchor" href="#题型技巧" aria-label="Permalink to &quot;题型技巧&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">题型</th><th style="text-align:left;">技巧</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>细节题</strong></td><td style="text-align:left;">定位原文，仔细比对，防偷换概念</td></tr><tr><td style="text-align:center;"><strong>推理题</strong></td><td style="text-align:left;">不是原文直说，合理推断，不过度</td></tr><tr><td style="text-align:center;"><strong>主旨题</strong></td><td style="text-align:left;">看首尾段，不被细节迷惑</td></tr><tr><td style="text-align:center;"><strong>词义题</strong></td><td style="text-align:left;">看前后句，找定义/解释/逻辑</td></tr></tbody></table><h3 id="错误选项特征" tabindex="-1">错误选项特征 <a class="header-anchor" href="#错误选项特征" aria-label="Permalink to &quot;错误选项特征&quot;">​</a></h3><ul><li>原文照搬（推理题）</li><li>偷换概念（张冠李戴）</li><li>扩大/缩小范围</li><li>无中生有</li></ul><hr><h2 id="二、七选五" tabindex="-1">二、七选五 <a class="header-anchor" href="#二、七选五" aria-label="Permalink to &quot;二、七选五&quot;">​</a></h2><h3 id="解题步骤" tabindex="-1">解题步骤 <a class="header-anchor" href="#解题步骤" aria-label="Permalink to &quot;解题步骤&quot;">​</a></h3><ol><li>看选项，划关键词</li><li>读文章，抓结构</li><li>看空格位置（段首/中/尾）</li><li>找线索（代词、逻辑词、词汇复现）</li></ol><h3 id="线索类型" tabindex="-1">线索类型 <a class="header-anchor" href="#线索类型" aria-label="Permalink to &quot;线索类型&quot;">​</a></h3><ul><li><strong>代词</strong>：it, they, this, that（指代前文）</li><li><strong>逻辑词</strong>：however, therefore, besides</li><li><strong>词汇复现</strong>：同词、同义词、反义词</li></ul><hr><h2 id="三、完形填空" tabindex="-1">三、完形填空 <a class="header-anchor" href="#三、完形填空" aria-label="Permalink to &quot;三、完形填空&quot;">​</a></h2><h3 id="解题步骤-1" tabindex="-1">解题步骤 <a class="header-anchor" href="#解题步骤-1" aria-label="Permalink to &quot;解题步骤&quot;">​</a></h3><ol><li><strong>通读全文</strong>（不看选项，抓主旨）</li><li><strong>逐空分析</strong>（先易后难）</li><li><strong>上下文联系</strong>（逻辑、复现）</li><li><strong>复读检查</strong></li></ol><h3 id="常见线索" tabindex="-1">常见线索 <a class="header-anchor" href="#常见线索" aria-label="Permalink to &quot;常见线索&quot;">​</a></h3><ul><li>原词复现</li><li>同义/近义词</li><li>反义词</li><li>因果、转折、递进关系</li></ul><hr><h2 id="四、语法填空" tabindex="-1">四、语法填空 <a class="header-anchor" href="#四、语法填空" aria-label="Permalink to &quot;四、语法填空&quot;">​</a></h2><h3 id="有提示词-6-7个" tabindex="-1">有提示词（6-7个） <a class="header-anchor" href="#有提示词-6-7个" aria-label="Permalink to &quot;有提示词（6-7个）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">词性</th><th style="text-align:left;">考点</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>动词</strong></td><td style="text-align:left;">时态、语态、非谓语(to do/doing/done)、词性转换</td></tr><tr><td style="text-align:center;"><strong>名词</strong></td><td style="text-align:left;">单复数、所有格</td></tr><tr><td style="text-align:center;"><strong>形容词/副词</strong></td><td style="text-align:left;">比较级、词性转换(adj.↔adv.)</td></tr><tr><td style="text-align:center;"><strong>代词</strong></td><td style="text-align:left;">人称代词、物主代词、反身代词</td></tr><tr><td style="text-align:center;"><strong>数词</strong></td><td style="text-align:left;">基数词变序数词</td></tr></tbody></table><h3 id="无提示词-3-4个" tabindex="-1">无提示词（3-4个） <a class="header-anchor" href="#无提示词-3-4个" aria-label="Permalink to &quot;无提示词（3-4个）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">考点</th><th style="text-align:left;">情况</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>冠词</strong></td><td style="text-align:left;">a/an/the，固定搭配</td></tr><tr><td style="text-align:center;"><strong>介词</strong></td><td style="text-align:left;">in/on/at/for/with/of</td></tr><tr><td style="text-align:center;"><strong>连词</strong></td><td style="text-align:left;">and/but/or/because/that/which</td></tr><tr><td style="text-align:center;"><strong>代词</strong></td><td style="text-align:left;">it（形式主语/宾语）</td></tr></tbody></table><hr><h2 id="五、写作模板" tabindex="-1">五、写作模板 <a class="header-anchor" href="#五、写作模板" aria-label="Permalink to &quot;五、写作模板&quot;">​</a></h2><h3 id="书信开头" tabindex="-1">书信开头 <a class="header-anchor" href="#书信开头" aria-label="Permalink to &quot;书信开头&quot;">​</a></h3><p><strong>建议信</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I am writing to offer some suggestions on [topic].</span></span></code></pre></div><p><strong>申请信</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I am writing to apply for [position].</span></span>
<span class="line"><span>I believe I am qualified for this position.</span></span></code></pre></div><p><strong>感谢信</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I am writing to express my sincere gratitude for [help].</span></span></code></pre></div><p><strong>道歉信</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I am writing to apologize for [mistake].</span></span></code></pre></div><h3 id="书信结尾" tabindex="-1">书信结尾 <a class="header-anchor" href="#书信结尾" aria-label="Permalink to &quot;书信结尾&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>I am looking forward to your reply.</span></span>
<span class="line"><span>Yours sincerely,</span></span>
<span class="line"><span>Li Hua</span></span></code></pre></div><h3 id="主体段落连接词" tabindex="-1">主体段落连接词 <a class="header-anchor" href="#主体段落连接词" aria-label="Permalink to &quot;主体段落连接词&quot;">​</a></h3><p><strong>递进</strong>：</p><ul><li>First(ly), ... Second(ly), ... Finally, ...</li><li>Besides, In addition, What&#39;s more, Furthermore</li></ul><p><strong>转折</strong>：</p><ul><li>However, Nevertheless, While, On the contrary</li></ul><p><strong>因果</strong>：</p><ul><li>Therefore, Thus, As a result, Consequently</li></ul><p><strong>举例</strong>：</p><ul><li>For example, For instance</li></ul><p><strong>总结</strong>：</p><ul><li>In conclusion, To sum up, All in all</li></ul><h3 id="高级句型" tabindex="-1">高级句型 <a class="header-anchor" href="#高级句型" aria-label="Permalink to &quot;高级句型&quot;">​</a></h3><p><strong>定语从句</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>As is known to all, ...</span></span>
<span class="line"><span>Those who ... tend to ...</span></span></code></pre></div><p><strong>非谓语</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Faced with ..., we should ...</span></span>
<span class="line"><span>Having done ..., sb. did ...</span></span></code></pre></div><p><strong>倒装</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Only in this way can we ...</span></span>
<span class="line"><span>Not only does he ..., but he also ...</span></span></code></pre></div><p><strong>强调</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>It is ... that ...</span></span></code></pre></div><p><strong>虚拟</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>If I were you, I would ...</span></span>
<span class="line"><span>Without ..., I would have ...</span></span></code></pre></div><h3 id="高级词汇替换" tabindex="-1">高级词汇替换 <a class="header-anchor" href="#高级词汇替换" aria-label="Permalink to &quot;高级词汇替换&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">普通</th><th style="text-align:center;">高级</th></tr></thead><tbody><tr><td style="text-align:center;">important</td><td style="text-align:center;">significant, essential, vital, crucial</td></tr><tr><td style="text-align:center;">good</td><td style="text-align:center;">beneficial, favorable, excellent</td></tr><tr><td style="text-align:center;">think</td><td style="text-align:center;">believe, consider, maintain</td></tr><tr><td style="text-align:center;">very</td><td style="text-align:center;">extremely, remarkably</td></tr><tr><td style="text-align:center;">more and more</td><td style="text-align:center;">increasingly, an increasing number of</td></tr><tr><td style="text-align:center;">help</td><td style="text-align:center;">assist, contribute to</td></tr><tr><td style="text-align:center;">want to</td><td style="text-align:center;">intend to, be eager to</td></tr><tr><td style="text-align:center;">because of</td><td style="text-align:center;">due to, thanks to</td></tr></tbody></table><hr><h2 id="六、易错点提醒" tabindex="-1">六、易错点提醒 <a class="header-anchor" href="#六、易错点提醒" aria-label="Permalink to &quot;六、易错点提醒&quot;">​</a></h2><h3 id="阅读" tabindex="-1">阅读 <a class="header-anchor" href="#阅读" aria-label="Permalink to &quot;阅读&quot;">​</a></h3><ul><li>注意题目问的是&quot;正确&quot;还是&quot;不正确&quot;</li><li>推理题不要选原文直接说的</li><li>主旨题不要被细节迷惑</li></ul><h3 id="完形" tabindex="-1">完形 <a class="header-anchor" href="#完形" aria-label="Permalink to &quot;完形&quot;">​</a></h3><ul><li>先通读全文再做题</li><li>注意上下文逻辑</li></ul><h3 id="语法填空" tabindex="-1">语法填空 <a class="header-anchor" href="#语法填空" aria-label="Permalink to &quot;语法填空&quot;">​</a></h3><ul><li>动词先判断是谓语还是非谓语</li><li>无提示词优先考虑冠词、介词、连词</li></ul><h3 id="写作" tabindex="-1">写作 <a class="header-anchor" href="#写作" aria-label="Permalink to &quot;写作&quot;">​</a></h3><ul><li>格式正确（书信有称呼落款）</li><li>时态一致</li><li>书写工整</li></ul><hr><p><strong>文档编号</strong>: Eng-Review-Tool-002<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,77)])])}const u=e(s,[["render",i]]);export{p as __pageData,u as default};
